import React from 'react';
import { Link, useLocation } from 'react-router-dom';

const Navbar = () => {
  const location = useLocation();
  return (
    <nav className="bg-sriLanka-orange text-white px-6 py-4 shadow-md flex items-center justify-between">
      <div className="font-bold text-xl">
        Janaya360
      </div>
      <div className="flex space-x-6 items-center">
        <Link to="/" className={location.pathname === '/' ? 'font-bold underline' : 'hover:text-sriLanka-maroon transition'}>Home</Link>
        <Link to="/politicians" className={location.pathname === '/politicians' ? 'font-bold underline' : 'hover:text-sriLanka-maroon transition'}>Politicians</Link>
        <Link to="/promises" className={location.pathname === '/promises' ? 'font-bold underline' : 'hover:text-sriLanka-maroon transition'}>Promises</Link>
        <Link to="/feedback" className={location.pathname === '/feedback' ? 'font-bold underline' : 'hover:text-sriLanka-maroon transition'}>Feedback</Link>
        <Link to="/news" className={location.pathname === '/news' ? 'font-bold underline' : 'hover:text-sriLanka-maroon transition'}>News</Link>
        <Link to="/notifications" className={location.pathname === '/notifications' ? 'font-bold underline' : 'hover:text-sriLanka-maroon transition'}>Notifications</Link>
        <Link to="/register" className="ml-6 px-4 py-2 border border-white text-white rounded-lg font-semibold hover:bg-white hover:text-sriLanka-orange transition">
          Register
        </Link>
        <Link to="/login" className="ml-2 px-4 py-2 bg-white text-sriLanka-orange rounded-lg font-semibold hover:bg-sriLanka-maroon hover:text-white transition">
          Login
        </Link>
      </div>
    </nav>
  );
};

export default Navbar;
